clear all; %[output:7b4ec957] %[output:9d28bb17]
close all;
addpath(genpath('utils'));
%%
%% Set simulation parameters
r = 0.03;
d = 0.165;
T_SIMULATION = 10;
Q_INITIAL = [0;0;0];
%%
%[text] ## Set input - Wheel velocities
%[text] sim\_1\_1
%%
% set input

OMEGA_L = 10; % Left wheel velocity
OMEGA_R = 10; % Right wheel velocity
%%
OMEGA_L = 10;
OMEGA_R = 5;
%%
OMEGA_L = 5;
OMEGA_R = 10;
%%
OMEGA_L = 10;
OMEGA_R = -10;
%%
% Plot results

modelName = 'sim_1_1';
simOut = sim(modelName);

% Extract state data
q_data = simOut.get('q_sim');
q_vector = q_data.signals.values;
%%
% Create a new figure and call the function
figure('Name', 'Simulation Result'); %[output:8a995c5d]

% Call the function from the utils folder. 
% 50 is the downsampling factor: it will draw the robot's heading every 50 samples.
plot_unicycle_2D(q_vector, 50); %[output:8a995c5d]
title(['Robot Trajectory - ' modelName]); %[output:8a995c5d]
%%
%[text] ## Set input - Unicycle velocities
%[text] sim\_1\_2
%%
% set input

v = 5; w = 0;
%%
v = 0; w = 10;
%%
v = 5; w = 10;
%%
% Plot results

modelName = 'sim_1_2';
simOut = sim(modelName); %[output:647224b9]

% Extract state data
q_data = simOut.get('q_sim');
q_plot = squeeze(q_data.signals.values)';
t_q = q_data.time;

z_data = simOut.get('z_sim');
z_plot = squeeze(z_data.signals.values)';
t_z = z_data.time; 

v_ch_data = simOut.get('v_chained_sim');
v_ch_plot = squeeze(v_ch_data.signals.values)';
t_v = v_ch_data.time;
%%
figure('Name', 'Simulation Result'); %[output:112536e7]

plot_unicycle_2D(q_plot, 50); %[output:112536e7]
title(['Robot Trajectory - ' modelName]); %[output:112536e7]
%%
%[text] ## Chained form
% same input as 1_2
%%
% OPTIONAL
v = 0; w = 2.0;
T_SIMULATION = 1;
Q_INITIAL = [1;1;0];

u_vector = [v; w]
%%
figure('Name', 'Confronto Modelli', 'Position', [100 100 1000 400]); %[output:083982e8]

% Left: q e u
subplot(1, 2, 1); %[output:083982e8]
plot(t_q, q_plot, 'LineWidth', 1.5);  %[output:77fba3cf]
hold on; grid on;
% Usiamo t_u per u_plot!
plot(t_u, u_plot, '--', 'LineWidth', 1.5);
title('Modello Unicycle (q, u)');
xlabel('Tempo [s]');
legend('x', 'y', '\theta', 'v', '\omega', 'Location', 'best');

% Right: z e v_chained
subplot(1, 2, 2);
plot(t_z, z_plot, 'LineWidth', 1.5); 
hold on; grid on;
% Usiamo t_v per v_ch_plot!
plot(t_v, v_ch_plot, '--', 'LineWidth', 1.5);
title('Chained Form (z, v_{chained})');
xlabel('Tempo [s]');
legend('z_1', 'z_2', 'z_3', 'v_1', 'v_2', 'Location', 'best');

%%
% Plot x (first component of q_vector) over time in a new figure
figure('Name', 'x(t) - First Component of q_vector'); %[output:44adc449]
% q_vector has shape [1 x 1 x T] according to the note: use squeeze to get [T x 1]
x_vals = squeeze(q_vector(1,1,:)); % results in [T x 1]
% Ensure t matches length
if numel(t) ~= numel(x_vals)
    t_plot = linspace(0, T_SIMULATION, numel(x_vals))';
else
    t_plot = t;
end
plot(t_plot, x_vals, 'LineWidth', 1.5); %[output:44adc449]
grid on; %[output:44adc449]
xlabel('Tempo [s]'); %[output:44adc449]
ylabel('x [m]'); %[output:44adc449]
title('Prima componente di q\_vector: x(t)'); %[output:44adc449]

